<span class="line"><span style="color:#A6E3A1;">                &quot;path&quot;</span><span style="color:#94E2D5;">:</span><span style="color:#CDD6F4;"> dir</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">path</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">to_string_lossy</span><span style="color:#9399B2;">()</span></span>
